import java.util.*;

public class Backtracking {

    // ── Subsets ─────────────────────────────────────────────────────────────
    public static List<List<Integer>> subsets(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        backtrackSubsets(nums, 0, new ArrayList<>(), result);
        return result;
    }
    private static void backtrackSubsets(int[] nums, int start,
                                         List<Integer> current, List<List<Integer>> result) {
        result.add(new ArrayList<>(current)); // every state is a valid subset
        for (int i = start; i < nums.length; i++) {
            current.add(nums[i]);                    // choose
            backtrackSubsets(nums, i + 1, current, result); // explore
            current.remove(current.size() - 1);     // unchoose
        }
    }

    // ── Permutations ────────────────────────────────────────────────────────
    public static List<List<Integer>> permute(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        backtrackPermute(nums, new boolean[nums.length], new ArrayList<>(), result);
        return result;
    }
    private static void backtrackPermute(int[] nums, boolean[] used,
                                          List<Integer> current, List<List<Integer>> result) {
        if (current.size() == nums.length) { result.add(new ArrayList<>(current)); return; }
        for (int i = 0; i < nums.length; i++) {
            if (used[i]) continue;
            used[i] = true;            current.add(nums[i]);
            backtrackPermute(nums, used, current, result);
            used[i] = false;           current.remove(current.size() - 1);
        }
    }

    // ── N-Queens ────────────────────────────────────────────────────────────
    public static List<List<String>> solveNQueens(int n) {
        List<List<String>> result = new ArrayList<>();
        int[] queens = new int[n]; // queens[row] = column of queen in that row
        Arrays.fill(queens, -1);
        nQueensHelper(n, 0, queens, new HashSet<>(), new HashSet<>(), new HashSet<>(), result);
        return result;
    }
    private static void nQueensHelper(int n, int row, int[] queens,
                                      Set<Integer> cols, Set<Integer> diag1, Set<Integer> diag2,
                                      List<List<String>> result) {
        if (row == n) { result.add(buildBoard(queens, n)); return; }
        for (int col = 0; col < n; col++) {
            if (cols.contains(col) || diag1.contains(row - col)
                    || diag2.contains(row + col)) continue; // pruning
            queens[row] = col;
            cols.add(col); diag1.add(row - col); diag2.add(row + col);
            nQueensHelper(n, row + 1, queens, cols, diag1, diag2, result);
            queens[row] = -1;
            cols.remove(col); diag1.remove(row - col); diag2.remove(row + col);
        }
    }
    private static List<String> buildBoard(int[] queens, int n) {
        List<String> board = new ArrayList<>();
        for (int q : queens) {
            char[] row = new char[n]; Arrays.fill(row, '.');
            row[q] = 'Q'; board.add(new String(row));
        }
        return board;
    }
}

import java.util.*;

public class Greedy {

    // ── Non-overlapping Intervals (Activity Selection) ─────────────────────
    public static int maxActivities(int[][] intervals) {
        Arrays.sort(intervals, Comparator.comparingInt(a -> a[1])); // sort by end
        int count = 0, lastEnd = Integer.MIN_VALUE;
        for (int[] interval : intervals) {
            if (interval[0] >= lastEnd) { // start >= last end
                count++;
                lastEnd = interval[1];
            }
        }
        return count;
    }

    // ── Minimum Number of Platforms (trains at a station) ─────────────────
    public static int minPlatforms(int[] arrivals, int[] departures) {
        Arrays.sort(arrivals); Arrays.sort(departures);
        int platforms = 0, maxPlatforms = 0;
        int i = 0, j = 0;
        while (i < arrivals.length) {
            if (arrivals[i] <= departures[j]) { platforms++; i++; }
            else { platforms--; j++; }
            maxPlatforms = Math.max(maxPlatforms, platforms);
        }
        return maxPlatforms;
    }

    // ── Jump Game — can you reach the end? ────────────────────────────────
    public static boolean canJump(int[] nums) {
        int maxReach = 0;
        for (int i = 0; i < nums.length; i++) {
            if (i > maxReach) return false; // stuck
            maxReach = Math.max(maxReach, i + nums[i]);
        }
        return true;
    }

    // ── Jump Game II — minimum jumps ──────────────────────────────────────
    public static int minJumps(int[] nums) {
        int jumps = 0, currentEnd = 0, farthest = 0;
        for (int i = 0; i < nums.length - 1; i++) {
            farthest = Math.max(farthest, i + nums[i]);
            if (i == currentEnd) { jumps++; currentEnd = farthest; }
        }
        return jumps;
    }

    // ── Fractional Knapsack ───────────────────────────────────────────────
    public static double fractionalKnapsack(int[] weights, int[] values, int W) {
        int n = weights.length;
        Double[] ratios = new Double[n];
        for (int i = 0; i < n; i++) ratios[i] = (double) values[i] / weights[i];
        Integer[] idx = new Integer[n];
        for (int i = 0; i < n; i++) idx[i] = i;
        Arrays.sort(idx, (a, b) -> Double.compare(ratios[b], ratios[a])); // desc ratio

        double total = 0;
        for (int i : idx) {
            if (W >= weights[i]) { total += values[i]; W -= weights[i]; }
            else { total += ratios[i] * W; break; }
        }
        return total;
    }
}
